var e=[{id:`L2_1`,type:`narration`,speaker:null,text:{KOREA:`오랜 방황 끝에 간신히 도달한 길이.`,JPN:`長らく彷徨った末にやっとたどり着いた道が……`,ENG:`The road I reached after a long wandering...`,TWN:`在徬徨那麼長的一段時間後，好不容易抵達的路…`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`narration`,speaker:null,text:{KOREA:`사실은, 막다른 길이었을지도 모른다.`,JPN:`実は、行き止まりだったのかもしれない。`,ENG:`It may have been a dead-end road.`,TWN:`或許是死路一條。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`KARIN_DELTA_NEXT_NULL`,text:{KOREA:`전술 무장 교체, 5번 무장!`,JPN:`戦術武装交換、5番武装！`,ENG:`Exchanging Tactical Gear to Gear No. 5!`,TWN:`更換戰術裝備，5號裝備！`},stage:{bg:`COUNTERSIDE_RED_ADF`,slots:{L:null,C:{char_id:`KARIN_DELTA_NEXT_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`KARIN_DELTA_NEXT_NULL`,text:{KOREA:`크윽!!`,JPN:`くっ！！`,ENG:`Kgh!!`,TWN:`咳呃！！`},stage:{bg:`COUNTERSIDE_RED_ADF`,slots:{L:null,C:{char_id:`KARIN_DELTA_NEXT_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`KING_EXILER_NULL_NULL`,text:{KOREA:`<color=#ff3636>그게 전부인가.</color>`,JPN:`<color=#ff3636>その程度か。</color>`,ENG:`<color=#ff3636>Is this all you've got?</color>`,TWN:`<color=#ff3636>這就完了嗎。</color>`},stage:{bg:`COUNTERSIDE_RED_ADF`,slots:{L:null,C:{char_id:`KING_EXILER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`KARIN_DELTA_NEXT_NULL`,text:{KOREA:`웃기지 마, 팔라디움 방벽 사출!`,JPN:`ふざけないで、パラディウム防壁射出！`,ENG:`As if! Deploying Palladium Bulwark!`,TWN:`別說笑了，發射守護神屏障！`},stage:{bg:`COUNTERSIDE_RED_ADF`,slots:{L:null,C:{char_id:`KARIN_DELTA_NEXT_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L15_1`,type:`narration`,speaker:null,text:{KOREA:`아무리 노력한다고 해도 다가오는 결말을 바꿀 방법 같은 건`,JPN:`いくら努力しても、迫りくる結末を変える方法なんて。`,ENG:`Perhaps, from the start, there was no way to alter our pending doom...`,TWN:`無論再怎麼努力，但能夠改變結局的方法…`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`narration`,speaker:null,text:{KOREA:`처음부터 존재하지 않았을지도 모른다.`,JPN:`最初から存在しなかったのかもしれない。`,ENG:`No matter how hard we tried.`,TWN:`或許從一開始就不存在。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`KING_EXILER_NULL_NULL`,text:{KOREA:`<color=#ff3636>가소롭군.</color>`,JPN:`<color=#ff3636>くだらん。</color>`,ENG:`<color=#ff3636>Pathetic.</color>`,TWN:`<color=#ff3636>真可笑。</color>`},stage:{bg:`COUNTERSIDE_RED_ADF`,slots:{L:null,C:{char_id:`KING_EXILER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`KING_EXILER_NULL_NULL`,text:{KOREA:`<color=#ff3636>이 따위 조잡한 물건으로!</color>`,JPN:`<color=#ff3636>こんなチンケな道具で！</color>`,ENG:`<color=#ff3636>You think you can defeat me?!</color>`,TWN:`<color=#ff3636>靠著這種程度的攻擊！</color>`},stage:{bg:`COUNTERSIDE_RED_ADF`,slots:{L:null,C:{char_id:`KING_EXILER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`KING_EXILER_NULL_NULL`,text:{KOREA:`<color=#ff3636>이 몸을 쓰러트릴 수 있다고 생각하나?</color>`,JPN:`<color=#ff3636>俺を倒せると思うか？</color>`,ENG:`<color=#ff3636>With that crude toy?!</color>`,TWN:`<color=#ff3636>就想打敗我嗎！？</color>`},stage:{bg:`COUNTERSIDE_RED_ADF`,slots:{L:null,C:{char_id:`KING_EXILER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`KARIN_DELTA_NEXT_NULL`,text:{KOREA:`3번 무장, 로드 메이커!`,JPN:`3番武装、ロードメーカー！`,ENG:`Tactical Gear No. 3, Road Maker!`,TWN:`3號裝備，開路者！`},stage:{bg:`COUNTERSIDE_RED_ADF`,slots:{L:null,C:{char_id:`KARIN_DELTA_NEXT_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L23_1`,type:`narration`,speaker:null,text:{KOREA:`하지만 그럼에도 나아가는 발걸음을 멈출 수는 없다.`,JPN:`それでも進む足取りを止めるわけにはいかない。`,ENG:`But nevertheless, I can only keep moving forward.`,TWN:`但即便如此，也無法停下邁出的腳步。`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_FX_WAVE`,slots:{L:null,C:null,R:null}}},{id:`L25_1`,type:`dialog`,speaker:`KING_EXILER_NULL_NULL`,text:{KOREA:`<color=#ff3636>소용없다고 했을텐데!</color>`,JPN:`<color=#ff3636>無駄だと言ったはずだ！</color>`,ENG:`<color=#ff3636>Your resistance is futile!</color>`,TWN:`<color=#ff3636>我說過！這些！全部！沒有用！</color>`},stage:{bg:`COUNTERSIDE_RED_ADF`,slots:{L:null,C:{char_id:`KING_EXILER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`KARIN_DELTA_NEXT_NULL`,text:{KOREA:`맞아, 소용없을지도 모르겠지.`,JPN:`そうね、無駄なのかもしれない。`,ENG:`You’re right. It may be futile.`,TWN:`是的，這也許沒有用。`},stage:{bg:`COUNTERSIDE_RED_ADF`,slots:{L:null,C:{char_id:`KARIN_DELTA_NEXT_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};